<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">config</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">max_outer_turns </span><span style="color:#94E2D5;">&gt;</span><span style="color:#FAB387;"> 0</span></span>
